using Xunit; using Moq; using SkyCD.vNext.SDK; using SkyCD.vNext.SDK.Capabilities; using System.Collections.Generic; using System.Threading.Tasks; namespace SkyCD.Plugin.WebBrowser.Tests { public class MenuCommandExecutionTests { private readonly WebBrowserPlugin _plugin; private readonly Mock<IPluginHost> _mockHost; public MenuCommandExecutionTests() { _plugin = new WebBrowserPlugin(); _mockHost = new Mock<IPluginHost>(); _mockHost.Setup(h => h.GetPluginSettingsAsync()).ReturnsAsync(new Dictionary<string, object>()); } [Fact] public async Task ExecuteMenuCommandAsync_NotifiesOnInvalidUrl() { var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(new Dictionary<string, object> { { "url", "ftp://invalid.com" } }); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.NotifyUserAsync(It.Is<string>(m => m.Contains("Invalid URL scheme"))), Times.Once); } [Fact] public async Task ExecuteMenuCommandAsync_NotifiesOnLaunchFailure() { _mockHost.Setup(h => h.LaunchExternalUrlAsync(It.IsAny<string>())).ThrowsAsync(new System.Exception("Launch failed")); var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(new Dictionary<string, object> { { "url", "https://example.com" } }); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.NotifyUserAsync(It.Is<string>(m => m.Contains("Failed to open URL"))), Times.Once); } [Fact] public async Task ExecuteMenuCommandAsync_IgnoresNullContextProperties() { var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(null as Dictionary<string, object>); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.LaunchExternalUrlAsync("about:blank"), Times.Once); } } }